package com.establo.controller;
import com.establo.dto.HorseDto;import com.establo.service.HorseService;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.data.web.PageableDefault;import org.springframework.http.*;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;import org.springframework.web.multipart.MultipartFile;import java.util.List;
@RestController @RequestMapping("/api/horses") @RequiredArgsConstructor public class HorseController {private final HorseService s;@GetMapping List<HorseDto> all(){return s.findAll();}@GetMapping("/search") Page<HorseDto> search(@RequestParam(required=false)String q,@PageableDefault(size=20,sort="name")Pageable pageable){return s.search(q,pageable);}@GetMapping("/{id}") HorseDto one(@PathVariable Long id){return s.find(id);}@GetMapping("/{id}/photo") ResponseEntity<byte[]> photo(@PathVariable Long id){var photo=s.photo(id);return ResponseEntity.ok().contentType(MediaType.parseMediaType(photo.contentType())).cacheControl(CacheControl.noCache()).body(photo.data());}@PostMapping @PreAuthorize("hasAnyRole('ADMIN','CAREGIVER')") ResponseEntity<HorseDto> create(@Valid @RequestBody HorseDto d){return ResponseEntity.status(201).body(s.create(d));}@PutMapping("/{id}") @PreAuthorize("hasAnyRole('ADMIN','CAREGIVER')") HorseDto update(@PathVariable Long id,@Valid @RequestBody HorseDto d){return s.update(id,d);}@PostMapping(value="/{id}/photo",consumes=MediaType.MULTIPART_FORM_DATA_VALUE) @PreAuthorize("hasAnyRole('ADMIN','CAREGIVER')") HorseDto uploadPhoto(@PathVariable Long id,@RequestPart("file") MultipartFile file){return s.updatePhoto(id,file);}@DeleteMapping("/{id}") @PreAuthorize("hasRole('ADMIN')") @ResponseStatus(HttpStatus.NO_CONTENT) void delete(@PathVariable Long id){s.delete(id);}}
